// Load texture from embedded PNG data
static inline Texture2D SPRITE8X8LoadEmbedded(void) {
    Image img = LoadImageFromMemory(".png", ATLAS8X8_PATH_DATA, ATLAS8X8_PATH_DATA_SIZE);
    Texture2D tex = LoadTextureFromImage(img);
    UnloadImage(img);
    return tex;
}

